function starHTML(avg){avg=Math.max(0,Math.min(5,Number(avg)||0));const full=Math.floor(avg),half=(avg-full)>=0.5;let html='';for(let i=1;i<=5;i++){if(i<=full)html+='<i class="f">★</i>';else if(half&&i===full+1)html+='<i class="h">★</i>';else html+='<i>★</i>';}return html;}
function repeatStr(ch,n){let s='';for(let i=0;i<n;i++)s+=ch;return s;}
async function loadSummary(barber){try{const r=await fetch(`${CAL_BASE}/public/reviews?barber=${encodeURIComponent(barber)}&t=${Date.now()}`,{cache:'no-store'});return await r.json();}catch(_){return{avg:0,count:0,items:[]};}}
async function refreshModal(barber){
const wrap=document.getElementById('review-modal');
const metrics=document.getElementById('metrics');const list=document.getElementById('list');
if(wrap)wrap.classList.add('reviews-loading');
const data=await loadSummary(barber);
const text=(data&&data.count)?`Average: ${data.avg||0}★ • ${data.count} reviews`:'Average — • 0 reviews';
if(metrics)metrics.textContent=text;
if(!list)return;
const items=(data.items||[]).slice().reverse();
list.innerHTML=items.map(r=>{const rating=+r.rating||0;const name=r.name||'Anonymous';const textR=(r.text||'').replace(/</g,'&lt;').replace(/>/g,'&gt;');return`<div class="item"><div class="r">${repeatStr('★',rating)}${repeatStr('☆',5-rating)}</div><div class="n">${name}</div><div class="t">${textR}</div></div>`;}).join('');
if(wrap)wrap.classList.remove('reviews-loading');
}
