let RV_RATING = 0;
function wireStars(){
const stars=document.querySelectorAll('#rv-stars span');
function paint(val){
stars.forEach(s=>{s.style.color=Number(s.dataset.val)<=val?'var(--gold)':'rgba(255,255,255,.22)';});
}
stars.forEach(s=>{
s.addEventListener('mouseenter',()=>paint(Number(s.dataset.val)));
s.addEventListener('mouseleave',()=>paint(RV_RATING));
s.addEventListener('click',()=>{RV_RATING=Number(s.dataset.val);paint(RV_RATING);});
});
}
