const PREFERRED=["Men's Haircut","Men's Haircut & Beard Trim","Clipper Only","Kids' Haircut","Beard Trim & Shaping"];
function prefIndex(name){name=String(name||'');const i=PREFERRED.findIndex(x=>name.toLowerCase().includes(String(x).toLowerCase()));return i>=0?i:1e9;}
function sortServices(arr){return(arr||[]).slice().sort((a,b)=>{const ia=prefIndex(a.name),ib=prefIndex(b.name);if(ia!==ib)return ia-ib;const ap=a.priceCents??0,bp=b.priceCents??0;if(ap!==bp)return bp-ap;const ad=a.durationMs??0,bd=b.durationMs??0;if(ad!==bd)return bd-ad;return(a.name||'').localeCompare(b.name||'');});}
