function yyyymm(y,m){return`${y}-${String(m+1).padStart(2,'0')}`;}
function isSameDay(a,b){return a&&b&&a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()&&a.getDate()===b.getDate();}
function clampToToday(d){const t=new Date();t.setHours(0,0,0,0);return d<t?t:d;}
function renderCalendar(){
const monthEl=$('calMonth');const daysEl=$('calDays');const noteEl=$('calNote');if(!monthEl||!daysEl||!noteEl)return;
const y=BOOK.calYear;const m=BOOK.calMonth;
monthEl.textContent=new Date(y,m,1).toLocaleDateString(undefined,{month:'long',year:'numeric'});
const first=new Date(y,m,1);const startDow=first.getDay();const daysInMonth=new Date(y,m+1,0).getDate();const prevDays=new Date(y,m,0).getDate();
const key=yyyymm(y,m);const monthMap=BOOK.calAvailMap.get(key)||new Map();
const today=new Date();today.setHours(0,0,0,0);
let html='';
for(let i=0;i<42;i++){
const dayNum=i-startDow+1;let d=null;let label='';let cls='cal-day';let muted=false;
if(dayNum<1){label=String(prevDays+dayNum);muted=true;d=new Date(y,m-1,prevDays+dayNum);}
else if(dayNum>daysInMonth){label=String(dayNum-daysInMonth);muted=true;d=new Date(y,m+1,dayNum-daysInMonth);}
else{label=String(dayNum);d=new Date(y,m,dayNum);}
if(muted)cls+=' muted';if(isSameDay(d,today))cls+=' today';if(BOOK.selectedDate&&isSameDay(d,BOOK.selectedDate))cls+=' sel';
const isInThisMonth=(d.getFullYear()===y&&d.getMonth()===m);let disabled=false;
if(isInThisMonth&&d<today)disabled=true;
const svcs=selectedServices();const hasServices=svcs.length>0;
const windowStart=new Date(today);const windowEnd=new Date(today);windowEnd.setDate(windowEnd.getDate()+6);
const withinWindow=isInThisMonth&&hasServices&&d>=windowStart&&d<=windowEnd;
const barberSched=getPublicBarberSchedule(BOOK.barber,BOOK.barberServerId||getBarberServerId(BOOK.barber),d);
const isFutureOrToday=isInThisMonth&&hasServices&&d>=windowStart&&barberSched.days.includes(d.getDay());
if(isInThisMonth&&!hasServices)disabled=true;
else if(isInThisMonth&&hasServices&&!barberSched.days.includes(d.getDay()))disabled=true;
else if(withinWindow){const avail=!!monthMap.get(d.getDate());if(avail)cls+=' avail';else disabled=true;}
else if(isFutureOrToday)cls+=' avail';
if(disabled)cls+=' disabled';
html+=`<button type="button" class="${cls}" data-date="${d.toISOString()}">${label}</button>`;
}
daysEl.innerHTML=html;noteEl.textContent='';
daysEl.querySelectorAll('.cal-day').forEach(btn=>{btn.addEventListener('click',async()=>{if(btn.classList.contains('disabled'))return;const iso=btn.getAttribute('data-date');if(!iso)return;const d=new Date(iso);const chosen=new Date(d.getFullYear(),d.getMonth(),d.getDate());BOOK.selectedDate=chosen;if(chosen.getFullYear()!==BOOK.calYear||chosen.getMonth()!==BOOK.calMonth){BOOK.calYear=chosen.getFullYear();BOOK.calMonth=chosen.getMonth();}clearSlotsUI();renderCalendar();updateSummary();await loadSlotsForSelectedDate().catch(err=>setErr(err?.message||String(err),2));updateNext2State();});});
updateNext2State();
}
async function refreshCalendarAvailability(){
const svcs=selectedServices();const noteEl=$('calNote');if(!noteEl)return;
if(!svcs.length){const key=yyyymm(BOOK.calYear,BOOK.calMonth);BOOK.calAvailMap.set(key,new Map());renderCalendar();return;}
const y=BOOK.calYear;const m=BOOK.calMonth;const key=yyyymm(y,m);
const today=new Date();today.setHours(0,0,0,0);const windowEnd=new Date(today);windowEnd.setDate(windowEnd.getDate()+6);
const runKey=`${BOOK.barber}|${key}|${[...BOOK.selectedIds].sort().join(',')}|7d`;BOOK.calBusyKey=runKey;
const monthMap=new Map();BOOK.calAvailMap.set(key,monthMap);
const firstOfMonth=new Date(y,m,1,0,0,0,0);const lastOfMonth=new Date(y,m+1,0,23,59,59,999);
const overlapsWindow=!(lastOfMonth<today||firstOfMonth>windowEnd);
if(!overlapsWindow){noteEl.textContent='';renderCalendar();return;}
setErr('',2);noteEl.textContent='';
try{
const daysInMonth=new Date(y,m+1,0).getDate();const daysToCheck=[];
for(let day=1;day<=daysInMonth;day++){const d0=new Date(y,m,day,0,0,0,0);if(d0>=today&&d0<=windowEnd)daysToCheck.push(day);}
const limit=3;let idx=0;
const workers=Array.from({length:limit},async()=>{while(idx<daysToCheck.length){const day=daysToCheck[idx++];if(BOOK.calBusyKey!==runKey)return;const dayStart=new Date(y,m,day,0,0,0,0);const dayEnd=new Date(y,m,day,23,59,59,999);const slots=await fetchAvailableSlotsServer({barberId:BOOK.barber,dayStart,dayEnd,services:svcs});monthMap.set(day,Array.isArray(slots)&&slots.length>0);}});
await Promise.all(workers);if(BOOK.calBusyKey!==runKey)return;noteEl.textContent='';renderCalendar();
}catch(err){console.warn('refreshCalendarAvailability error',err);noteEl.textContent='Select a date — available times will load after you click.';renderCalendar();}
}
async function fetchAvailableSlotsServer({barberId,dayStart,dayEnd,services}){
const ds=dayStart?new Date(dayStart):null;const de=dayEnd?new Date(dayEnd):null;
if(!ds||!de||Number.isNaN(ds.getTime())||Number.isNaN(de.getTime()))return[];
const realBarberId=getBarberServerId(barberId);
if(!realBarberId||realBarberId.includes('PUT_FIRESTORE_BARBER_DOC_ID_'))throw new Error('Missing Firestore barber document id for '+String(barberId||''));
const duration_minutes=Math.max(1,Math.round(totalDurationMinutes(services)||30));
const sched=getPublicBarberSchedule(barberId,realBarberId,ds);
if(!sched.days.includes(ds.getDay()))return[];
const requestStart=new Date(ds);requestStart.setDate(requestStart.getDate()-1);requestStart.setHours(0,0,0,0);
const requestEnd=new Date(de);requestEnd.setDate(requestEnd.getDate()+1);requestEnd.setHours(23,59,59,999);
const data=await postJSON(CAL.availability,{barber_id:realBarberId,start_at:isoZ(requestStart),end_at:isoZ(requestEnd),duration_minutes});
const targetDayKey=localDateKey(ds);
const availRaw=Array.isArray(data?.availabilities)?data.availabilities:[];
const slotsRaw=availRaw.length?availRaw.filter(x=>String(x?.local_day||'')===targetDayKey).map(x=>x?.start_at):(Array.isArray(data?.slots)?data.slots:[]);
return slotsRaw.map(s=>parseSlotDateSmart(s,ds,sched)).filter(d=>!Number.isNaN(d.getTime())).map(d=>alignSlotToSelectedDay(d,ds)).filter(d=>!Number.isNaN(d.getTime())).filter(d=>isSameLocalDate(d,ds)).filter(d=>slotMatchesSchedule(d,ds,sched)).sort((a,b)=>a.getTime()-b.getTime());
}
async function loadSlotsForSelectedDate(){
const svcs=selectedServices();if(!svcs.length)throw new Error('Select services first.');if(!BOOK.selectedDate)throw new Error('Select a date.');
setErr('',2);clearSlotsUI();
const d=BOOK.selectedDate;const dayStart=new Date(d.getFullYear(),d.getMonth(),d.getDate(),0,0,0,0);const dayEnd=new Date(d.getFullYear(),d.getMonth(),d.getDate(),23,59,59,999);
const slots=await fetchAvailableSlotsServer({barberId:BOOK.barber,dayStart,dayEnd,services:svcs});
const barberSched=getPublicBarberSchedule(BOOK.barber,BOOK.barberServerId||getBarberServerId(BOOK.barber),d);
BOOK.slots=(slots||[]).slice().sort((a,b)=>a-b).filter(t=>!Number.isNaN(t.getTime()));
BOOK.slots=BOOK.slots.filter((t,i,arr)=>{if(!isSameLocalDate(t,d))return false;if(!slotMatchesSchedule(t,d,barberSched))return false;return i===arr.findIndex(x=>localSlotKey(x)===localSlotKey(t));});
const durationMin=Math.max(1,Math.round(totalDurationMinutes(svcs)||30));const rawFreeSet=new Set(BOOK.slots.map(localSlotKey));
BOOK.slots=BOOK.slots.filter(t=>rawFreeSet.has(localSlotKey(t)));
renderSlots();updateSummary();updateNext2State();
}
