function closeBookingModal(){
const wrap=$('booking-modal');if(!wrap)return;
wrap.classList.remove('open');document.body.classList.remove('modal-open');setTimeout(()=>{wrap.style.display='none';},220);
}
function wireBookingModal(){
(function lockToVertical(){
const sheet=document.querySelector('#booking-modal .bm-sheet');if(!sheet)return;
let sx=0,sy=0;
sheet.addEventListener('touchstart',e=>{const t=e.touches&&e.touches[0];if(!t)return;sx=t.clientX;sy=t.clientY;},{passive:true});
sheet.addEventListener('touchmove',e=>{const t=e.touches&&e.touches[0];if(!t)return;const dx=Math.abs(t.clientX-sx);const dy=Math.abs(t.clientY-sy);if(dx>dy+2)e.preventDefault();},{passive:false});
sheet.addEventListener('wheel',e=>{if(Math.abs(e.deltaX)>Math.abs(e.deltaY))e.preventDefault();},{passive:false});
})();
$('booking-modal')?.addEventListener('click',e=>{if(e.target===$('booking-modal'))closeBookingModal();});
$('bm-close')?.addEventListener('click',closeBookingModal);
let _phoneLookupTimer=null;
$('phone')?.addEventListener('input',()=>{
setErr('',3);
CLIENT_FLOW={checked:false,existing:false,clientId:'',firstName:'',lastName:'',email:'',phone:''};
BOOK.clientReady=false;
const extra=$('clientExtraFields');if(extra)extra.style.display='none';
setClientLookupMessage('');
updateSummary();
if(_phoneLookupTimer)clearTimeout(_phoneLookupTimer);
const raw=String($('phone')?.value||'').replace(/\D/g,'');
if(raw.length<10){setClientLookupMessage(raw?'Enter full phone number.':'');return;}
_phoneLookupTimer=setTimeout(async()=>{
try{await checkClientByPhone();setErr('',3);}catch(err){setErr(err?.message||String(err),3);}finally{updateSummary();}
},450);
});
$('btnSendBookCode')?.addEventListener('click',()=>bookSendCode());
$('btnVerifyBookCode')?.addEventListener('click',()=>bookVerifyCode());
$('bookCode')?.addEventListener('keydown',(e)=>{if(e.key==='Enter'){e.preventDefault();bookVerifyCode();}});
wireHaircutPhotoInput();
$('smsConsent')?.addEventListener('change',()=>{
const wrap=$('smsConsentWrap');
if(wrap){wrap.classList.toggle('checked',!!$('smsConsent')?.checked);}
updateSummary();
});
['firstName','lastName','email'].forEach(id=>$(id)?.addEventListener('input',()=>updateSummary()));
$('next1')?.addEventListener('click',async()=>{if(!selectedServices().length){setErr('Select at least one service to continue.',1);return;}setWizardStep(2);await refreshCalendarAvailability().catch(()=>{});});
$('back2')?.addEventListener('click',()=>setWizardStep(1));
$('next2')?.addEventListener('click',()=>{if(!BOOK.selectedDate){setErr('Select a date to continue.',2);return;}if(!BOOK.chosenSlot){setErr('Choose a time to continue.',2);return;}setWizardStep(3);});
$('back3')?.addEventListener('click',()=>setWizardStep(2));
$('calPrev')?.addEventListener('click',()=>{BOOK.calMonth-=1;if(BOOK.calMonth<0){BOOK.calMonth=11;BOOK.calYear-=1;}BOOK.selectedDate=null;clearSlotsUI();renderCalendar();updateSummary();refreshCalendarAvailability().catch(()=>{});});
$('calNext')?.addEventListener('click',()=>{BOOK.calMonth+=1;if(BOOK.calMonth>11){BOOK.calMonth=0;BOOK.calYear+=1;}BOOK.selectedDate=null;clearSlotsUI();renderCalendar();updateSummary();refreshCalendarAvailability().catch(()=>{});});
$('confirmBooking')?.addEventListener('click',async()=>{
const btn=$('confirmBooking');
try{
setErr('',3);setOk('');
const first=String($('firstName')?.value||'').trim();const last=String($('lastName')?.value||'').trim();
const phone=String($('phone')?.value||'').trim();const email=String($('email')?.value||'').trim();const note=String($('note')?.value||'').trim();
if(!phone)throw new Error('Enter phone number.');const svcs=selectedServices();if(!svcs.length)throw new Error('Select at least one service.');if(!BOOK.chosenSlot)throw new Error('Choose a time.');
if(btn)btn.disabled=true;
const{clientId}=await ensureClientForBooking();
const bookingId=await createBookingServer({barberId:BOOK.barber,startAt:BOOK.chosenSlot,clientId,services:svcs,note:note||null});
const when=BOOK.chosenSlot.toLocaleString([],{weekday:'short',month:'short',day:'numeric',hour:'numeric',minute:'2-digit'});
const svcText=svcs.map(s=>s.name).join(', ');
const clientNameForSuccess=CLIENT_FLOW.existing?[CLIENT_FLOW.firstName,CLIENT_FLOW.lastName].filter(Boolean).join(' '):[first,last].filter(Boolean).join(' ');
closeBookingModal();
openSuccessModal(`<b>Your appointment is booked.</b><br><br><b>Client:</b> ${clientNameForSuccess||'Client'}<br><b>Barber:</b> ${BOOK.barber}<br><b>When:</b> ${when}<br><b>Services:</b> ${svcText}<br><b>Total:</b> ${totalDurationMinutes(svcs)} min • ${moneyCentsToUsd(totalPriceCents(svcs))}<br><br><span style="color:rgba(255,255,255,.65)">Confirmation ID: ${bookingId}</span><br><br><span style="color:rgba(255,207,63,.85);font-size:12px;">⚠ SMS confirmations and reminders are temporarily unavailable. Please save your booking details.</span>`);
}catch(err){setErr(err?.message||String(err),3);if(btn)btn.disabled=false;}finally{updateSummary();}
});
}
function wireBookButtons(){document.querySelectorAll('.btn[data-action="book"]').forEach(btn=>{btn.addEventListener('click',e=>{e.preventDefault();const card=btn.closest('.barber');const barber=card?.dataset?.barber||'';openBookingModal(barber);});});}
function wireAbout(){document.querySelectorAll('.js-about').forEach(btn=>{btn.addEventListener('click',()=>{const barber=btn.getAttribute('data-about-for')||'';const card=document.querySelector(`.barber[data-barber="${barber}"]`);if(!card)return;const opening=!card.classList.contains('more-open');document.querySelectorAll('.barber.more-open').forEach(x=>{if(x!==card)x.classList.remove('more-open');});card.classList.toggle('more-open',opening);if(opening)renderAllRadars();});});}
let SERVICES_LOAD_PROMISE=null;
async function preloadAllServices(){
if(Array.isArray(BOOK.allServices)&&BOOK.allServices.length)return BOOK.allServices;
if(SERVICES_LOAD_PROMISE)return SERVICES_LOAD_PROMISE;
SERVICES_LOAD_PROMISE=(async()=>{
try{
const data=await postJSON(CAL.services,{});const arr=Array.isArray(data?.services)?data.services:[];
BOOK.allServices=arr.map(s=>{
const durMs=s.durationMs!=null?Number(s.durationMs):s.duration_minutes!=null?Number(s.duration_minutes)*60000:0;
const price=s.priceCents!=null?Number(s.priceCents):s.price_cents!=null?Number(s.price_cents):0;
const id=s.id!=null?String(s.id):s.service_id!=null?String(s.service_id):s.docId!=null?String(s.docId):'';
const barberIdsRaw=Array.isArray(s.barber_ids)?s.barber_ids:Array.isArray(s.barberIds)?s.barberIds:Array.isArray(s.assigned_barbers)?s.assigned_barbers:Array.isArray(s.barbers)?s.barbers:[];
return{id,name:String(s.name||''),durationMs:durMs,priceCents:price,version:String(s.version??'1'),barberIds:barberIdsRaw.map(x=>String(x||'').trim()).filter(Boolean)};
}).filter(s=>s.id&&s.name);
}catch(e){console.warn('preloadAllServices error',e);BOOK.allServices=[];}
finally{const ok=Array.isArray(BOOK.allServices)&&BOOK.allServices.length;if(!ok)SERVICES_LOAD_PROMISE=null;}
return BOOK.allServices;
})();
return SERVICES_LOAD_PROMISE;
}
async function ensureAllServicesLoaded(){if(Array.isArray(BOOK.allServices)&&BOOK.allServices.length)return;await preloadAllServices();}
function openPortfolioLightbox(url){
let overlay=document.getElementById('portfolio-lightbox');
if(!overlay){
overlay=document.createElement('div');
overlay.id='portfolio-lightbox';
overlay.style.cssText='position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,.88);backdrop-filter:blur(18px);-webkit-backdrop-filter:blur(18px);display:flex;align-items:center;justify-content:center;padding:16px;opacity:0;transition:opacity .25s ease;cursor:zoom-out;';
overlay.innerHTML='<img id="portfolio-lightbox-img" style="max-width:92vw;max-height:88vh;border-radius:14px;object-fit:contain;box-shadow:0 20px 60px rgba(0,0,0,.5);transform:scale(.95);transition:transform .25s ease;" />';
overlay.addEventListener('click',function(){closePortfolioLightbox();});
document.body.appendChild(overlay);
}
var img=document.getElementById('portfolio-lightbox-img');
if(img)img.src=url;
overlay.style.display='flex';
requestAnimationFrame(function(){overlay.style.opacity='1';if(img)img.style.transform='scale(1)';});
document.body.classList.add('modal-open');
}
function closePortfolioLightbox(){
var overlay=document.getElementById('portfolio-lightbox');
if(!overlay)return;
var img=document.getElementById('portfolio-lightbox-img');
overlay.style.opacity='0';
if(img)img.style.transform='scale(.95)';
setTimeout(function(){overlay.style.display='none';},250);
document.body.classList.remove('modal-open');
}
async function boot(){
try{
wireBookingModal();
loadBarbersFromServer().then(()=>{renderBarbersFromServer();renderAllRadars();wireModal();wireBookButtons();wireAbout();setWorkStatus();hydrateSummaries();}).catch(err=>console.warn('bootBarbersFromServer error',err));
startConfigSync();
await preloadAllServices();
}catch(err){console.error('boot() failed:',err);}
}
window.addEventListener('load',()=>{boot();var y=document.getElementById('yr');if(y)y.textContent=new Date().getFullYear();});
